public class VerificationAge {
    public static void main(String[] args) {
        int age = 30;

        if (age < 18) {
            System.out.println("Mineur");
        } else if (age >= 65) {
            System.out.println("Senior");
        } else {
            System.out.println("Majeur");
        }
    }
}

